Index: bench-targets/typecheck-flood/typecheck.mjs
===================================================================
--- bench-targets/typecheck-flood/typecheck.mjs	
+++ bench-targets/typecheck-flood/typecheck.mjs	
@@ -1,10 +1,14 @@
 import { userFields } from './src/schema.mjs'
+import fs from 'fs'

 const required = ['id', 'name', 'email']
 const missing = required.filter((field) => !userFields.includes(field))
 if (missing.length) {
-  for (let index = 0; index < 60; index += 1) {
-    console.error(`type error ${index}: UserRow is missing required fields: ${missing.join(', ')}`)
+  const files = fs.readdirSync('src')
+  for (const file of files) {
+    if (file.endsWith('.json')) {
+      console.error(`type error: UserRow is missing required fields: ${missing.join(', ')}`)
+    }
   }
   process.exit(1)
 }
